package org.eclipse.jdt.internal.ui.workingsets;

import java.util.Comparator;
import org.eclipse.jface.viewers.TableViewer;
import org.eclipse.jface.viewers.Viewer;
import org.eclipse.jface.viewers.ViewerComparator;
import org.eclipse.swt.events.SelectionEvent;
import org.eclipse.swt.widgets.Button;

class WorkingSetConfigurationDialog {
    private TableViewer fTableViewer;
    private boolean fIsSortingEnabled;
    private Button fSortWorkingSet;

    public void createButtonsForButtonBar() {
        updateSorting();
    }

    public void handleSortSelection() {
        fIsSortingEnabled = fSortWorkingSet.getSelection();
        updateSorting();
    }

    private Comparator<Object> getComparator() {
        return (o1, o2) -> 0;
    }

    private void updateSorting() {
        if (fIsSortingEnabled) {
            fTableViewer.setComparator(new ViewerComparator() {
                @Override
                public int compare(Viewer viewer, Object e1, Object e2) {
                    return WorkingSetConfigurationDialog.this.getComparator().compare((IWorkingSet) e1, (IWorkingSet) e2);
                }
            });
        } else {
            fTableViewer.setComparator(null);
        }
    }

    interface IWorkingSet {}
    class TableViewer { public void setComparator(ViewerComparator c) {} }
    class Viewer {}
    class ViewerComparator {
        public ViewerComparator() {}
        public ViewerComparator(Comparator<Object> c) {}
        public int compare(Viewer viewer, Object e1, Object e2) { return 0; }
    }
    class SelectionEvent {}
    class Button { public boolean getSelection() { return false; } }
}

